async function sendEmail(sendGridApiKey, emailTo) {
    const url = `https://api.sendgrid.com/v3/mail/send`;
    const msg = {
        "personalizations": [{
            "to": [{"email": emailTo}],
            "subject": "Sending with SendGrid is Fun"
        }],
        "from": {"email": "test@example.com"},
        "content": [{"type": "text/plain", "value": "and easy to do anywhere, even with Node.js"}]
    };
    
    let response = await fetch(url, {
        method: 'post',
        headers: {
            'Authorization': `Bearer ${sendGridApiKey}`,
            'Content-Type': 'application/json'
        },
        body: JSON.stringify(msg)
    });
    
    if (!response.ok) throw "Failed to send email";
}

async function sendSMS(twilioAccountSid, smsTo) {
    const url = `https://api.twilio.com/2010-04-01/Accounts/${twilioAccountSid}/Messages.json`;
    
    let response = await fetch(url, {
        method: 'post',
        headers: {
            'Authorization': `Basic ${Buffer.from(twilioAccountSid + ':').toString('base64')}`,
            'Content-Type': 'application/x-www-form-urlencoded'
        },
        body: new URLSearchParams({
            To: smsTo, 
            From: "+1234567890", // Your Twilio number
            Body: "This is the ship that made the Kessel Run in fourteen parsecs?" 
        })
    });
    
    if (!response.ok) throw "Failed to send SMS";
}